/* global Accelerometer, GravitySensor, Gyroscope */
import React, {
  useEffect,
  useState,
  useContext,
  createContext,
  useMemo,
} from "react";
import {
  Card,
  Typography,
  Grid,
  Box,
  useTheme,
} from "@mui/material";
import {
  ResponsiveContainer,
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
} from "recharts";
import { useInView } from "react-intersection-observer";

// Context for managing sensor data
const SensorContext = createContext();

// CircularBuffer class for efficient data handling
class CircularBuffer {
  constructor(size) {
    this.size = size;
    this.buffer = [];
  }

  push(item) {
    if (this.buffer.length >= this.size) {
      this.buffer.shift();
    }
    this.buffer.push(item);
  }

  get data() {
    return [...this.buffer];
  }
}

// Generic max-min tracker hook
const useMaxMinTracker = (initialData = {}) => {
  const [max, setMax] = useState(initialData);
  const [min, setMin] = useState(initialData);

  const update = (newData) => {
    setMax((prevMax) => ({
      ...prevMax,
      ...Object.keys(newData).reduce((acc, key) => {
        acc[key] = Math.max(prevMax[key] || -Infinity, newData[key]);
        return acc;
      }, {}),
    }));
    setMin((prevMin) => ({
      ...prevMin,
      ...Object.keys(newData).reduce((acc, key) => {
        acc[key] = Math.min(prevMin[key] || Infinity, newData[key]);
        return acc;
      }, {}),
    }));
  };

  return { max, min, update };
};

// Hook for accelerometer data
const useAccelerometer = () => {
  const [data, setData] = useState({});
  const { max, min, update } = useMaxMinTracker();
  const buffer = useMemo(() => new CircularBuffer(100), []);
  const [chartData, setChartData] = useState([]);

  useEffect(() => {
    if (!("Accelerometer" in window)) return;

    try {
      const accelerometer = new Accelerometer({ frequency: 30 });
      accelerometer.addEventListener("reading", () => {
        const newData = {
          x: accelerometer.x / 9.8,
          y: accelerometer.y / 9.8,
          z: accelerometer.z / 9.8,
        };
        setData(newData);
        update(newData);
        buffer.push({ ...newData, timestamp: Date.now() });
        setChartData(buffer.data);
      });
      accelerometer.start();

      return () => accelerometer.stop();
    } catch (err) {
      console.error("Accelerometer error:", err);
    }
  }, [buffer, update]);

  return { data, max, min, chartData };
};

// Hook for gravity sensor data
const useGravitySensor = () => {
  const [data, setData] = useState({});
  const { max, min, update } = useMaxMinTracker();
  const buffer = useMemo(() => new CircularBuffer(100), []);
  const [chartData, setChartData] = useState([]);

  useEffect(() => {
    if (!("GravitySensor" in window)) return;

    try {
      const gravity = new GravitySensor({ frequency: 30 });
      gravity.addEventListener("reading", () => {
        const newData = {
          x: gravity.x / 9.8,
          y: gravity.y / 9.8,
          z: gravity.z / 9.8,
        };
        setData(newData);
        update(newData);
        buffer.push({ ...newData, timestamp: Date.now() });
        setChartData(buffer.data);
      });
      gravity.start();

      return () => gravity.stop();
    } catch (err) {
      console.error("GravitySensor error:", err);
    }
  }, [buffer, update]);

  return { data, max, min, chartData };
};

// Hook for gyroscope data
const useGyroscope = () => {
  const [data, setData] = useState({});
  const { max, min, update } = useMaxMinTracker();
  const buffer = useMemo(() => new CircularBuffer(100), []);
  const [chartData, setChartData] = useState([]);

  useEffect(() => {
    if (!("Gyroscope" in window)) return;

    try {
      const gyroscope = new Gyroscope({ frequency: 30 });
      gyroscope.addEventListener("reading", () => {
        const newData = {
          x: gyroscope.x,
          y: gyroscope.y,
          z: gyroscope.z,
        };
        setData(newData);
        update(newData);
        buffer.push({ ...newData, timestamp: Date.now() });
        setChartData(buffer.data);
      });
      gyroscope.start();

      return () => gyroscope.stop();
    } catch (err) {
      console.error("Gyroscope error:", err);
    }
  }, [buffer, update]);

  return { data, max, min, chartData };
};

// Hook for device orientation
const useDeviceOrientation = () => {
  const [data, setData] = useState({});
  const { max, min, update } = useMaxMinTracker();
  const buffer = useMemo(() => new CircularBuffer(100), []);
  const [chartData, setChartData] = useState([]);

  useEffect(() => {
    const handleOrientationEvent = (event) => {
      const { alpha, beta, gamma } = event;
      if (
        typeof alpha === "number" &&
        typeof beta === "number" &&
        typeof gamma === "number"
      ) {
        const newData = { pitch: beta, roll: gamma, yaw: alpha };
        setData(newData);
        update(newData);
        buffer.push({ ...newData, timestamp: Date.now() });
        setChartData(buffer.data);
      }
    };

    window.addEventListener("deviceorientation", handleOrientationEvent);

    return () =>
      window.removeEventListener("deviceorientation", handleOrientationEvent);
  }, [buffer, update]);

  return { data, max, min, chartData };
};

// Combine all sensors into a single provider
export const SensorProvider = ({ children }) => {
  const accelerometer = useAccelerometer();
  const gravity = useGravitySensor();
  const gyroscope = useGyroscope();
  const orientation = useDeviceOrientation();

  return (
    <SensorContext.Provider
      value={{
        accelerometer,
        gravity,
        gyroscope,
        orientation,
      }}
    >
      {children}
    </SensorContext.Provider>
  );
};

export const useSensor = (sensorType) => {
  const context = useContext(SensorContext);
  if (!context) {
    throw new Error("useSensor must be used within SensorProvider");
  }
  return context[sensorType];
};

// Sensor chart component
const SensorChart = ({ data, colors }) => {
  const { ref, inView } = useInView();

  return (
    <Box ref={ref} sx={{ height: 250 }}>
      {inView ? (
        <ResponsiveContainer width="100%" height="100%">
          <LineChart data={data}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="timestamp" hide={true} />
            <YAxis />
            <Tooltip transitionDuration={0} />
            {Object.keys(data[0] || {})
              .filter((key) => key !== "timestamp")
              .map((axis) => (
                <Line
                  key={axis}
                  type="monotone"
                  dataKey={axis}
                  stroke={colors[axis]}
                  dot={false}
                />
              ))}
          </LineChart>
        </ResponsiveContainer>
      ) : (
        <Typography>Loading...</Typography>
      )}
    </Box>
  );
};

const SensorSection = () => {
  const { accelerometer, gravity, gyroscope, orientation } =
    useContext(SensorContext);
  const theme = useTheme();
  const colors = {
    x: theme.palette.mode === "dark" ? "#8884d8" : "#0000ff",
    y: theme.palette.mode === "dark" ? "#82ca9d" : "#008000",
    z: theme.palette.mode === "dark" ? "#ffc658" : "#ffcc00",
    pitch: theme.palette.mode === "dark" ? "#8884d8" : "#0000ff",
    roll: theme.palette.mode === "dark" ? "#82ca9d" : "#008000",
    yaw: theme.palette.mode === "dark" ? "#ffc658" : "#ffcc00",
  };

  const sensors = [
    { name: "Accelerometer", data: accelerometer },
    { name: "Gravity", data: gravity },
    { name: "Gyroscope", data: gyroscope },
    { name: "Orientation", data: orientation },
  ];

  return sensors.map((sensor) => (
    <Grid item xs={12} md={6} lg={4} key={sensor.name}>
      <Card sx={{ height: 500, mb: 4 }}>
        <Box sx={{ height: 200, overflow: "auto", p: 2 }}>
          <Typography variant="h5">{sensor.name}</Typography>
          {Object.entries(sensor.data.data).map(([key, value]) => (
            <Typography key={key} style={{ color: colors[key] }}>
              {`${key.toUpperCase()}: ${value?.toFixed(
                4
              )} (Max: ${sensor.data.max[key]?.toFixed(
                4
              )}, Min: ${sensor.data.min[key]?.toFixed(4)})`}
            </Typography>
          ))}
        </Box>
        <SensorChart data={sensor.data.chartData} colors={colors} />
      </Card>
    </Grid>
  ));
};

const SensorPage = () => (
  <SensorProvider>
    <Grid container spacing={4} sx={{ py: 4, px: 2 }}>
      <SensorSection />
    </Grid>
  </SensorProvider>
);

export default SensorPage;
